// ============================================================
// 節點：指令解析（規則式，不依賴 AI）
// 功能：解析使用者自然語言 query，輸出標準 JSON
// ============================================================

// -------------------- CONFIG 區塊 --------------------
const CONFIG = {
  // 所有可用倉別
  warehouses: ['TAO1', 'TAO3', 'TAO4', 'TAO5', 'TAO6', 'TAO7', 'TAO10'],

  // 意圖識別關鍵字對照表（優先順序由上到下）
  intentKeywords: [
    { keywords: ['病假統計'], intent: 'sick_leave_stats' },
    { keywords: ['請假統計'], intent: 'leave_stats' },
    { keywords: ['請假狀況', '請假'], intent: 'leave_status' },
    { keywords: ['出勤人員', '出勤明細', '出勤報表'], intent: 'attendance_detail' },
    { keywords: ['出勤統計'], intent: 'attendance_stats' },
  ],

  // 假別關鍵字（用於從 query 中偵測指定假別）
  leaveTypeKeywords: [
    { keywords: ['病假', '病'], leaveType: '病假' },
    { keywords: ['事假', '事'], leaveType: '事假' },
    { keywords: ['特休', '特'], leaveType: '特休' },
    { keywords: ['曠職', '曠'], leaveType: '曠職' },
  ],
};
// -------------------- END CONFIG --------------------

const query = ($input.first().json.body?.query || '').trim();

if (!query) {
  return [{
    json: {
      success: false,
      error: '請提供查詢指令（query 欄位為空）',
      hint: '範例：4/2請假狀況、查詢TAO1 4/2病假',
    }
  }];
}

// --- 1. 解析日期 ---
function parseDate(q) {
  const now = new Date();
  const currentYear = now.getFullYear();
  // 格式：2026/4/2 或 2026-04-02
  let m = q.match(/(\d{4})[\/-](\d{1,2})[\/-](\d{1,2})/);
  if (m) {
    return `${m[1]}-${String(m[2]).padStart(2, '0')}-${String(m[3]).padStart(2, '0')}`;
  }
  // 格式：4/2 或 04/02（無年份）
  m = q.match(/(\d{1,2})[\/-](\d{1,2})/);
  if (m) {
    return `${currentYear}-${String(m[1]).padStart(2, '0')}-${String(m[2]).padStart(2, '0')}`;
  }
  return null;
}

// --- 2. 解析意圖 ---
function parseIntent(q) {
  for (const rule of CONFIG.intentKeywords) {
    for (const kw of rule.keywords) {
      if (q.includes(kw)) return rule.intent;
    }
  }
  return 'attendance_detail';
}

// --- 3. 解析倉別 ---
function parseWarehouses(q) {
  if (/全部倉|所有倉|全倉/.test(q)) return CONFIG.warehouses.slice();
  const found = [];
  for (const wh of CONFIG.warehouses) {
    if (q.toUpperCase().includes(wh)) found.push(wh);
  }
  return found.length > 0 ? found : CONFIG.warehouses.slice();
}

// --- 4. 解析假別 ---
function parseLeaveType(q) {
  for (const rule of CONFIG.leaveTypeKeywords) {
    for (const kw of rule.keywords) {
      if (q.includes(kw)) return rule.leaveType;
    }
  }
  return '';
}

function needReport(intent) {
  return ['sick_leave_stats', 'leave_stats', 'attendance_stats'].includes(intent);
}

const date = parseDate(query);
if (!date) {
  return [{
    json: {
      success: false,
      error: '無法解析日期，請在查詢中包含日期',
      hint: '支援格式：4/2、04/02、2026/4/2、2026-04-02',
      originalQuery: query,
    }
  }];
}

const intent = parseIntent(query);
const warehouse = parseWarehouses(query);
const leaveType = parseLeaveType(query);

return [{
  json: {
    success: true,
    parsed: {
      intent,
      date,
      warehouse,
      leaveType,
      needReport: needReport(intent),
    },
    originalQuery: query,
  }
}];

// ============================================================
// 節點：組裝讀取參數
// 功能：為每個倉別產生 Google Sheets API metadata URL
// ============================================================

// -------------------- CONFIG 區塊 --------------------
const CONFIG = {
  spreadsheetMap: {
    'TAO1':  '1_bhGQdx0YH7lsqPFEq5___6_Nwq_gbelJmIHv0bmaIE',
    'TAO3':  '1cffI2jIVZA1uSiAyaLLXXgPzDByhy87xznaN85O7wEE',
    'TAO4':  '1tVxQbV0298fn2OXWAF0UqZa7FLbypsatciatxs4YVTU',
    'TAO5':  '1jzVXC6gt36hJtlUHoxtTzZLMNj4EtTsd4k8eNB1bdiA',
    'TAO6':  '1wwPLSLjl2abfM_OMdTNI9PoiPKo3waCV_y0wmx2DxAE',
    'TAO7':  '16nGCqRO8DYDm0PbXFbdt-fiEFZCXxXjlOWjKU67p4LY',
    'TAO10': '1y0w49xdFlHvcVtgtG8fq6zdrF26y8j7HMFh5ujzUyR4',
  },
  intentSheetType: {
    'leave_status':      'leave',
    'sick_leave_stats':  'leave',
    'leave_stats':       'leave',
    'attendance_detail': 'work',
    'attendance_stats':  'work',
  },
  sheetKeywords: {
    leave: ['班表', '出勤記錄', '假況'],
    work:  ['出勤時數', '出勤時間', '工時'],
  },
};
// -------------------- END CONFIG --------------------

const parsed = $input.first().json.parsed;
const warehouses = parsed.warehouse;
const intent = parsed.intent;
const sheetType = CONFIG.intentSheetType[intent] || 'leave';
const keywords = CONFIG.sheetKeywords[sheetType];

const results = [];
for (const wh of warehouses) {
  const spreadsheetId = CONFIG.spreadsheetMap[wh];
  if (!spreadsheetId) continue;
  results.push({
    json: {
      warehouse: wh,
      spreadsheetId,
      sheetType,
      sheetKeywords: keywords,
      intent,
      date: parsed.date,
      leaveType: parsed.leaveType,
      needReport: parsed.needReport,
      originalQuery: $input.first().json.originalQuery,
      metaUrl: `https://sheets.googleapis.com/v4/spreadsheets/${spreadsheetId}?fields=sheets.properties.title`,
    }
  });
}

return results;

// ============================================================
// 節點：解析分頁名稱，組裝資料讀取 URL
// 功能：根據分頁關鍵字找到目標分頁，產出讀取資料的 URL
// ============================================================

const CONFIG = {
  sheetKeywords: {
    leave: ['班表', '出勤記錄', '假況'],
    work:  ['出勤時數', '出勤時間', '工時'],
  },
};

// 從前面節點取得原始參數（透過 $('組裝讀取參數') 取得）
let prevData;
try {
  prevData = $('組裝讀取參數').first().json;
} catch(e) {
  prevData = $input.first().json;
}

const metaResponse = $input.first().json;
const warehouse = prevData.warehouse;
const spreadsheetId = prevData.spreadsheetId;
const sheetType = prevData.sheetType;
const keywords = CONFIG.sheetKeywords[sheetType] || CONFIG.sheetKeywords.leave;

// 檢查 API 回應是否有錯誤
if (metaResponse.error || !metaResponse.sheets) {
  return [{
    json: {
      ...prevData,
      allSheetNames: [],
      warning: `${warehouse} 無法取得分頁列表：${metaResponse.error?.message || JSON.stringify(metaResponse)}`,
      dataUrl: '',
      success: false,
    }
  }];
}

const allSheetNames = metaResponse.sheets.map(s => s.properties.title);

// 根據關鍵字找目標分頁
let targetSheet = null;
let warning = null;
for (const kw of keywords) {
  const found = allSheetNames.find(name => name.includes(kw));
  if (found) {
    targetSheet = found;
    break;
  }
}
if (!targetSheet) {
  targetSheet = allSheetNames[0] || 'Sheet1';
  warning = `${warehouse} 找不到含有 [${keywords.join(', ')}] 的分頁，已退回使用「${targetSheet}」。所有分頁：${allSheetNames.join(', ')}`;
}

const dataUrl = `https://sheets.googleapis.com/v4/spreadsheets/${spreadsheetId}/values/${encodeURIComponent(targetSheet)}?majorDimension=ROWS`;

return [{
  json: {
    ...prevData,
    sheetName: targetSheet,
    allSheetNames,
    warning,
    dataUrl,
    success: true,
  }
}];

// ============================================================
// 節點：資料標準化
// 功能：將各倉原始資料映射為統一欄位格式
// ============================================================

// -------------------- CONFIG 區塊 --------------------
const CONFIG = {
  workFieldMapping: {
    date:           ['日期', 'Date', 'date'],
    department:     ['組別', '部門', 'Department', 'department', '組', 'Group'],
    shift:          ['班別', 'Shift', 'shift', '班次'],
    name:           ['姓名', 'Name', 'name', '員工姓名'],
    workHours:      ['工作總時數', '工時', 'Hours', 'workHours', 'Work Hours', '總工時'],
    overtimeHours:  ['加班總時數', 'OvertimeHours', 'Overtime Hours', 'overtimeHours', '加班時數', '加班'],
    note:           ['備註', 'Note', 'note', 'Remark', '說明'],
    attendanceStatus: ['出勤狀態', 'Status', 'status', 'attendanceStatus'],
    leaveType:      ['假況', '請假', 'LeaveType', 'leaveType', 'Leave Type', '假別'],
  },
  leaveStatusMapping: {
    '病假': '病假', '病': '病假', 'sick': '病假', 'sick leave': '病假',
    '事假': '事假', '事': '事假', 'personal leave': '事假',
    '特休': '特休', '特': '特休', 'annual leave': '特休',
    '曠職': '曠職', '曠': '曠職', 'absent': '曠職',
    '出勤': '出勤', '正常': '出勤', 'attendance': '出勤', 'present': '出勤',
    '休假': '休假', '休': '休假',
    '公假': '公假', '公': '公假',
    '產假': '產假', '喪假': '喪假', '婚假': '婚假',
  },
  leaveDateStartCol: 7,
};
// -------------------- END CONFIG --------------------

// 從前面節點取得參數
let prevData;
try {
  prevData = $('解析分頁並組裝URL').first().json;
} catch(e) {
  prevData = {};
}

const apiResponse = $input.first().json;
const warehouse = prevData.warehouse || '';
const sheetType = prevData.sheetType || 'work';
const sheetName = prevData.sheetName || '';
const allSheetNames = prevData.allSheetNames || [];
const date = prevData.date || '';
const intent = prevData.intent || '';
const leaveType = prevData.leaveType || '';
const needReport = prevData.needReport || false;
const originalQuery = prevData.originalQuery || '';
const prevWarning = prevData.warning || null;

// 檢查 API 回應
if (apiResponse.error || !apiResponse.values) {
  return [{
    json: {
      warehouse, sheetType, sheetName, allSheetNames, date, intent,
      leaveType, needReport, originalQuery,
      warning: prevWarning,
      rows: [],
      totalRows: 0,
      success: false,
      error: `${warehouse} 無法讀取分頁「${sheetName}」：${apiResponse.error?.message || '無資料'}`,
    }
  }];
}

const allRows = apiResponse.values || [];
const headers = allRows.length > 0 ? allRows[0] : [];
const rawRows = allRows.slice(1);

function findColumnIndex(hdrs, aliases) {
  for (const alias of aliases) {
    const idx = hdrs.findIndex(h => h && h.trim() === alias);
    if (idx !== -1) return idx;
  }
  return -1;
}

function normalizeLeaveStatus(val) {
  if (!val || val.trim() === '') return { status: '', resolved: true };
  const v = val.trim().toLowerCase();
  for (const [key, mapped] of Object.entries(CONFIG.leaveStatusMapping)) {
    if (v === key.toLowerCase()) return { status: mapped, resolved: true };
  }
  return { status: val.trim(), resolved: false, unresolvedStatus: true };
}

let standardizedRows = [];

if (sheetType === 'work') {
  const colMap = {};
  for (const [field, aliases] of Object.entries(CONFIG.workFieldMapping)) {
    colMap[field] = findColumnIndex(headers, aliases);
  }
  for (const row of rawRows) {
    const getVal = (field) => {
      const idx = colMap[field];
      return idx >= 0 && row[idx] !== undefined ? String(row[idx]).trim() : '';
    };
    const statusInfo = normalizeLeaveStatus(getVal('attendanceStatus') || getVal('leaveType'));
    standardizedRows.push({
      date: getVal('date'),
      department: getVal('department'),
      shift: getVal('shift'),
      name: getVal('name'),
      workHours: getVal('workHours'),
      overtimeHours: getVal('overtimeHours'),
      attendanceStatus: statusInfo.status,
      leaveType: statusInfo.status,
      note: getVal('note'),
      warehouse,
      ...(statusInfo.unresolvedStatus ? { unresolvedStatus: true } : {}),
    });
  }
} else {
  const dateStartCol = CONFIG.leaveDateStartCol;
  const nameColIdx = findColumnIndex(headers, ['姓名', 'Name', 'name', '員工姓名']);
  const deptColIdx = findColumnIndex(headers, ['組別', '部門', 'Department', 'department', '組', 'Group']);
  const shiftColIdx = findColumnIndex(headers, ['班別', 'Shift', 'shift', '班次']);
  const dateHeaders = headers.slice(dateStartCol);
  for (const row of rawRows) {
    const personName = nameColIdx >= 0 ? String(row[nameColIdx] || '').trim() : '';
    const dept = deptColIdx >= 0 ? String(row[deptColIdx] || '').trim() : '';
    const shift = shiftColIdx >= 0 ? String(row[shiftColIdx] || '').trim() : '';
    if (!personName) continue;
    for (let i = 0; i < dateHeaders.length; i++) {
      const cellValue = row[dateStartCol + i];
      if (cellValue === undefined || cellValue === null || String(cellValue).trim() === '') continue;
      const statusInfo = normalizeLeaveStatus(String(cellValue));
      standardizedRows.push({
        date: dateHeaders[i] ? String(dateHeaders[i]).trim() : '',
        department: dept,
        shift,
        name: personName,
        workHours: '',
        overtimeHours: '',
        attendanceStatus: statusInfo.status,
        leaveType: statusInfo.status,
        note: '',
        warehouse,
        ...(statusInfo.unresolvedStatus ? { unresolvedStatus: true } : {}),
      });
    }
  }
}

return [{
  json: {
    warehouse, sheetType, sheetName, allSheetNames, date, intent,
    leaveType, needReport, originalQuery,
    warning: prevWarning,
    rows: standardizedRows,
    totalRows: standardizedRows.length,
    success: true,
  }
}];

// ============================================================
// 節點：合併所有倉別資料
// ============================================================

const allItems = $input.all();
const mergedRows = [];
const warnings = [];
const errors = [];
let date = '';
let intent = '';
let leaveType = '';
let needReport = false;
let originalQuery = '';
const warehouseList = [];

for (const item of allItems) {
  const d = item.json;
  if (!date) date = d.date;
  if (!intent) intent = d.intent;
  if (!leaveType) leaveType = d.leaveType;
  if (!needReport) needReport = d.needReport;
  if (!originalQuery) originalQuery = d.originalQuery;
  warehouseList.push(d.warehouse);
  if (d.warning) warnings.push(d.warning);
  if (!d.success) {
    errors.push(d.error || `${d.warehouse} 讀取失敗`);
    continue;
  }
  if (d.rows && d.rows.length > 0) {
    mergedRows.push(...d.rows);
  }
}

return [{
  json: {
    date, intent, leaveType, needReport, originalQuery,
    warehouses: warehouseList,
    rows: mergedRows,
    totalRows: mergedRows.length,
    warnings: warnings.length > 0 ? warnings : undefined,
    errors: errors.length > 0 ? errors : undefined,
    success: errors.length === 0,
  }
}];

// ============================================================
// 節點：查詢與統計
// ============================================================

const CONFIG = {
  leaveCategories: ['病假', '事假', '特休', '曠職', '公假', '產假', '喪假', '婚假', '休假'],
  attendanceValues: ['出勤', '正常', ''],
};

const data = $input.first().json;
const { date, intent, leaveType, needReport, originalQuery, rows, warehouses, warnings, errors } = data;

function matchDate(rowDate, targetDate) {
  if (!rowDate || !targetDate) return false;
  const rd = String(rowDate).trim();
  const td = String(targetDate).trim();
  if (rd === td) return true;
  const parts = td.split('-');
  if (parts.length !== 3) return false;
  const tYear = parseInt(parts[0]);
  const tMonth = parseInt(parts[1]);
  const tDay = parseInt(parts[2]);
  const mdMatch = rd.match(/^(\d{1,2})[\/-](\d{1,2})$/);
  if (mdMatch) return parseInt(mdMatch[1]) === tMonth && parseInt(mdMatch[2]) === tDay;
  const fullMatch = rd.match(/^(\d{4})[\/-](\d{1,2})[\/-](\d{1,2})$/);
  if (fullMatch) return parseInt(fullMatch[1]) === tYear && parseInt(fullMatch[2]) === tMonth && parseInt(fullMatch[3]) === tDay;
  return false;
}

const dateFiltered = rows.filter(r => matchDate(r.date, date));
let result = {};

switch (intent) {
  case 'leave_status': {
    const leaveRows = dateFiltered.filter(r => {
      const st = r.attendanceStatus || r.leaveType || '';
      return st && !CONFIG.attendanceValues.includes(st);
    });
    const filteredRows = leaveType ? leaveRows.filter(r => (r.leaveType || r.attendanceStatus) === leaveType) : leaveRows;
    result = {
      success: true, query: originalQuery, intent, date,
      summaryText: `${date} 請假狀況：共 ${filteredRows.length} 人請假` + (leaveType ? `（${leaveType}）` : '') + `，涵蓋倉別：${warehouses.join(', ')}`,
      totals: { totalLeave: filteredRows.length, byWarehouse: {}, byLeaveType: {} },
      rows: filteredRows,
    };
    for (const r of filteredRows) {
      result.totals.byWarehouse[r.warehouse] = (result.totals.byWarehouse[r.warehouse] || 0) + 1;
      const lt = r.leaveType || r.attendanceStatus || '未分類';
      result.totals.byLeaveType[lt] = (result.totals.byLeaveType[lt] || 0) + 1;
    }
    break;
  }
  case 'sick_leave_stats': {
    const sickRows = dateFiltered.filter(r => (r.leaveType || r.attendanceStatus || '').trim() === '病假');
    result = {
      success: true, query: originalQuery, intent, date,
      summaryText: `${date} 病假統計：共 ${sickRows.length} 人病假，涵蓋倉別：${warehouses.join(', ')}`,
      totals: { totalSickLeave: sickRows.length, byWarehouse: {} },
      rows: sickRows,
    };
    for (const r of sickRows) result.totals.byWarehouse[r.warehouse] = (result.totals.byWarehouse[r.warehouse] || 0) + 1;
    break;
  }
  case 'leave_stats': {
    const leaveRows = dateFiltered.filter(r => {
      const st = r.attendanceStatus || r.leaveType || '';
      return st && !CONFIG.attendanceValues.includes(st);
    });
    result = {
      success: true, query: originalQuery, intent, date,
      summaryText: `${date} 請假統計：共 ${leaveRows.length} 人請假，涵蓋倉別：${warehouses.join(', ')}`,
      totals: { totalLeave: leaveRows.length, byWarehouse: {}, byLeaveType: {} },
      rows: leaveRows,
    };
    for (const r of leaveRows) {
      result.totals.byWarehouse[r.warehouse] = (result.totals.byWarehouse[r.warehouse] || 0) + 1;
      const lt = r.leaveType || r.attendanceStatus || '未分類';
      result.totals.byLeaveType[lt] = (result.totals.byLeaveType[lt] || 0) + 1;
    }
    break;
  }
  case 'attendance_detail': {
    result = {
      success: true, query: originalQuery, intent, date,
      summaryText: `${date} 出勤人員明細：共 ${dateFiltered.length} 筆資料，涵蓋倉別：${warehouses.join(', ')}`,
      totals: { totalRecords: dateFiltered.length, byWarehouse: {}, byDepartment: {}, byShift: {} },
      rows: dateFiltered,
    };
    for (const r of dateFiltered) {
      result.totals.byWarehouse[r.warehouse] = (result.totals.byWarehouse[r.warehouse] || 0) + 1;
      if (r.department) result.totals.byDepartment[r.department] = (result.totals.byDepartment[r.department] || 0) + 1;
      if (r.shift) result.totals.byShift[r.shift] = (result.totals.byShift[r.shift] || 0) + 1;
    }
    break;
  }
  case 'attendance_stats': {
    const totalWorkHours = dateFiltered.reduce((s, r) => s + (parseFloat(r.workHours) || 0), 0);
    const totalOT = dateFiltered.reduce((s, r) => s + (parseFloat(r.overtimeHours) || 0), 0);
    result = {
      success: true, query: originalQuery, intent, date,
      summaryText: `${date} 出勤統計：共 ${dateFiltered.length} 人，總工時 ${totalWorkHours.toFixed(1)}h，加班 ${totalOT.toFixed(1)}h，倉別：${warehouses.join(', ')}`,
      totals: { totalRecords: dateFiltered.length, totalWorkHours: totalWorkHours.toFixed(1), totalOvertimeHours: totalOT.toFixed(1), byWarehouse: {} },
      rows: dateFiltered,
    };
    for (const r of dateFiltered) {
      if (!result.totals.byWarehouse[r.warehouse]) result.totals.byWarehouse[r.warehouse] = { count: 0, workHours: 0, overtimeHours: 0 };
      result.totals.byWarehouse[r.warehouse].count++;
      result.totals.byWarehouse[r.warehouse].workHours += parseFloat(r.workHours) || 0;
      result.totals.byWarehouse[r.warehouse].overtimeHours += parseFloat(r.overtimeHours) || 0;
    }
    for (const wh of Object.keys(result.totals.byWarehouse)) {
      result.totals.byWarehouse[wh].workHours = result.totals.byWarehouse[wh].workHours.toFixed(1);
      result.totals.byWarehouse[wh].overtimeHours = result.totals.byWarehouse[wh].overtimeHours.toFixed(1);
    }
    break;
  }
  default: {
    result = { success: false, query: originalQuery, error: `無法識別的查詢意圖：${intent}` };
  }
}

if (warnings && warnings.length > 0) result.warnings = warnings;
if (errors && errors.length > 0) {
  result.errors = errors;
  if (result.rows && result.rows.length === 0) {
    result.success = false;
    result.summaryText = '查詢過程中部分倉別讀取失敗，請檢查 errors 欄位';
  }
}
if (result.rows && result.rows.length === 0 && result.success) {
  result.success = false;
  result.summaryText = `${date} 查無符合條件的資料（倉別：${warehouses.join(', ')}）`;
}

result.emailReady = true;
result.emailSubject = `[出勤報表] ${date} ${intent} - ${warehouses.join(', ')}`;
result.emailBody = result.summaryText || '';

return [{ json: result }];
